+  runTasksMaintenance,
+  runTasksNotify,
+  runTasksShow,
+} from "./cli.runtime.js";
+
+function parsePositiveIntOrUndefined(value: unknown): number | undefined {
+  if (typeof value !== "string" || !value.trim()) {
+    return undefined;
+  }
+  const parsed = Number.parseInt(value, 10);
+  return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined;
+}
