+  it("patches notify policy and exposes audit plus maintenance", async () => {
+    await withTaskStateDir(async () => {
+      const created = await defaultTaskOperationsRuntime.dispatch({
+        type: "create",
+        namespace: "tasks",
+        kind: "cli",
+        status: "running",
+        requesterSessionKey: "agent:test:main",
